// Vocabulary data: V1 (Solja), V2 (Ala), P2 (Glossary), EXTRA (deep vocab bank)
const V1=[
  {a:"طالما إحنا من ناحية",p:"tala ma ihna min nahyat",e:"As long as we're on this angle / from this side...",ctx:"Major pivot transition. Reframes the conversation from a new angle. Master this — it sounds natural instantly.",ex:"طالما إحنا من ناحية الشهرة، خلينا نتكلم عن الأصحاب.",exen:"Since we're on fame, let's talk about friends.",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"ألو هو / ألو إنو",p:"alu hwa / alu ino",e:"So that's it / which means / that means that",ctx:"The most important connector in Sudanese speech. 'Alu hwa' = so that's the thing. 'Alu ino' = so that means.",ex:"ألو هو الزول دا ما كان مستعد للشهرة.",exen:"So that's it — that person wasn't ready for fame.",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"حيث إنو",p:"haytho ino",e:"Given that / seeing as / since",ctx:"Slightly formal connector introducing a reason.",ex:"حيث إنو هو مجتهد، ما مستغرب النجاح.",exen:"Given that he's diligent, the success isn't surprising.",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"أما بعد",p:"ama ba3d",e:"Now then / moving on",ctx:"Classic opener signalling the move from preamble to main point.",ex:"أما بعد، خلينا نتكلم عن الأصحاب.",exen:"Now then, let's talk about friends.",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"راجع / راجعين لـ",p:"raji3 li",e:"Going back to / returning to the point",ctx:"Circle back to a previous topic mid-conversation.",ex:"راجعين لحتة أول أغنية...",exen:"Going back to the topic of the first song...",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"على قدر ما أنت",p:"3ala gadr ma anta",e:"To the extent that you / as much as you",ctx:"Proportional logic phrase. 'The world gives to the extent that you put in.'",ex:"الدنيا بتديك على قدر ما أنت بتجتهد.",exen:"The world gives to the extent that you work hard.",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"كوني كونيك",p:"kowni kownik",e:"You do you / be yourself",ctx:"Asserting mutual authenticity. Classic Sudanese phrase for everyone just being themselves.",ex:"كوني كونيك — ما لازم كلنا نكون نفس الشيء.",exen:"Be yourself — we don't all have to be the same.",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"سن صون / منها لي",p:"sin soon / min-ha li",e:"Anyway / moving along / from that then",ctx:"Conversational pivot filler like 'so from there...' or 'anyway, moving on.'",ex:"سن صون، لما نيجي للحتة بتاعت الأصحاب...",exen:"Anyway, moving to the friends topic...",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"إنو",p:"ino",e:"That / meaning that (conjunction)",ctx:"The Sudanese version of أن/إن. Used constantly. 'I feel that...' / 'the thing is that...'",ex:"بحس إنو الموضوع دا صعب شديد.",exen:"I feel that this matter is very difficult.",cat:"Transitions",src:"v1",type:"Transition"},
  {a:"فاهمني / فاهماني",p:"fahimni / fahimani",e:"You understand me? / you see what I mean?",ctx:"THE most important check-in in Sudanese Arabic. Used after almost every point.",ex:"الموضوع صعب — فاهماني؟",exen:"The matter is difficult — you understand?",cat:"Connectors",src:"v1",type:"Phrase"},
  {a:"يعني",p:"ya3ni",e:"I mean / meaning / you know / sort of",ctx:"The most universal filler in Arabic. Explains, softens, buys time.",ex:"يعني الزول دا رهيب شديد.",exen:"I mean, that person is incredibly amazing.",cat:"Connectors",src:"v1",type:"Word"},
  {a:"وبتاع / وبتاعت",p:"w-bita3",e:"And stuff / and things / and all that",ctx:"Trails off a list without naming everything. Like 'and all that jazz.'",ex:"في حفلات وبرفورمنس وبتاع.",exen:"There are shows and performances and stuff.",cat:"Connectors",src:"v1",type:"Word"},
  {a:"بالجد",p:"bil-jad",e:"Seriously / for real / genuinely",ctx:"Cuts through and emphasizes something is real. Most natural as a standalone.",ex:"بالجد هو غيّر المجال دا.",exen:"For real, he changed this field.",cat:"Emphasis",src:"v1",type:"Word"},
  {a:"صراحة",p:"saraha",e:"Honestly / to be frank / straight up",ctx:"Signals the real unfiltered truth is coming. Opens honest statements.",ex:"صراحة ما كنت واثق إنو ينجح.",exen:"Honestly I wasn't sure he'd succeed.",cat:"Emphasis",src:"v1",type:"Word"},
  {a:"شديد",p:"shadeed",e:"Very / extremely / intensely",ctx:"Sudanese intensifier. Goes after the thing it intensifies. 'صعب شديد' = extremely difficult.",ex:"المجال دا صعب شديد.",exen:"This field is extremely difficult.",cat:"Emphasis",src:"v1",type:"Word"},
  {a:"حرفياً",p:"harfeean",e:"Literally / exactly / I genuinely mean this",ctx:"Emphasis — you want the listener to know you're not exaggerating.",ex:"حرفياً الزول دا غيّر حياتي.",exen:"That person literally changed my life.",cat:"Emphasis",src:"v1",type:"Word"},
  {a:"رهيب / رهيبة",p:"rahib / rahiba",e:"Amazing / incredible / awesome",ctx:"Strong praise. One of the go-to compliment words in Sudanese Arabic.",ex:"البرفورمنس بتاعه كان رهيب شديد.",exen:"His performance was incredibly amazing.",cat:"Praise",src:"v1",type:"Word"},
  {a:"بالذات",p:"bil-zat",e:"Especially / specifically / particularly",ctx:"One of the most natural emphasis words. 'Especially in Sudanese society...'",ex:"بالذات في المجتمع السوداني الموضوع صعب.",exen:"Especially in Sudanese society this is difficult.",cat:"Emphasis",src:"v1",type:"Word"},
  {a:"الحمد لله",p:"al-hamdu lillah",e:"Praise God / thank God",ctx:"Used for gratitude, attributing success to God, and as a general affirmation.",ex:"الحمد لله على كل نجاح.",exen:"Praise God for every success.",cat:"Faith",src:"v1",type:"Phrase"},
  {a:"توفيق",p:"tawfeeq",e:"God-given success / divine facilitation",ctx:"Not just 'success' — specifically what comes through God's grace.",ex:"90% توفيق و10% اجتهاد.",exen:"90% divine grace and 10% effort.",cat:"Faith",src:"v1",type:"Word"},
  {a:"بركة",p:"baraka",e:"Blessing / divine grace that makes things work",ctx:"The invisible quality that makes effort fruitful.",ex:"ما في حاجة بتحصل بدون بركة من ربنا.",exen:"Nothing happens without God's blessing.",cat:"Faith",src:"v1",type:"Word"},
  {a:"سبحان الله",p:"subhan allah",e:"Glory to God / wow (divine awe)",ctx:"Used when something amazing happens by perfect timing or coincidence.",ex:"سبحان الله — الظروف دي ما كانت ممكنة قبل.",exen:"Glory to God — these circumstances weren't possible before.",cat:"Faith",src:"v1",type:"Phrase"},
  {a:"التمايز",p:"al-tamayuz",e:"Standing out / distinction / being uniquely different",ctx:"Core value. Not fitting in — carving your own space.",ex:"التمايز هو اللي خلاه يوصل للمكان دا.",exen:"Distinction is what got him to where he is.",cat:"Artistry",src:"v1",type:"Word"},
  {a:"فنان",p:"fanan",e:"Artist — one who creates from the soul",ctx:"Solja's distinction: a فنان has something real inside they must express.",ex:"الفنان بيبدع من حاجة حقيقية جوّاه.",exen:"An artist creates from something real inside them.",cat:"Artistry",src:"v1",type:"Word"},
  {a:"صناعي شاطر",p:"sona3y shater",e:"Skilled craftsman — excellent but not artistic",ctx:"Not an insult — someone who approaches work as a trade rather than as art.",ex:"ممكن تكون صناعي شاطر وتحقق نجاح كبير.",exen:"You can be a skilled craftsman and achieve great success.",cat:"Artistry",src:"v1",type:"Phrase"},
  {a:"بتنحت في الصخر",p:"betnhat fi as-sakhr",e:"Chiseling into rock / grinding persistently",ctx:"Metaphor for persistent hard work. Keep going even when you can't see the result.",ex:"لو فضلت تنحت في الصخر حتوصل.",exen:"If you keep chiseling at the rock, you'll get there.",cat:"Work ethic",src:"v1",type:"Phrase"},
  {a:"إخلاص / مخلص",p:"ikhlas / mukhlis",e:"Sincerity / deeply loyal and dedicated",ctx:"The highest quality praised in the podcast. Sincere to your work AND your people.",ex:"الزول المخلص بيكون مخلص لشغله ولأصحابه.",exen:"A loyal person is loyal to their work and their friends.",cat:"Values",src:"v1",type:"Word"},
  {a:"السيركل بتاعتي",p:"as-circle bata3ti",e:"My circle / my inner group",ctx:"English+Sudanese mix. The small trusted group always kept deliberately small.",ex:"السيركل بتاعتي دايماً ضيقة وأنا مبسوط بكدا.",exen:"My circle is always small and I'm happy with that.",cat:"Relationships",src:"v1",type:"Phrase"},
  {a:"اللي بيناتنا أكبر",p:"alli beiyna akbar",e:"What's between us is bigger (than what people see)",ctx:"Expressing the depth of a bond that outsiders can't fully see.",ex:"اللي بيناتنا أكبر من اللي الناس شايفينه.",exen:"What's between us is bigger than what people see.",cat:"Relationships",src:"v1",type:"Phrase"},
  {a:"امتحنت العلاقة",p:"imtahant al-3alaqa",e:"The relationship was tested",ctx:"When a friendship goes through difficult challenges.",ex:"كل مرة تنجح تمتحن علاقتك.",exen:"Every time you succeed your relationships get tested.",cat:"Relationships",src:"v1",type:"Phrase"},
  {a:"الكبريش",p:"al-kabreesh",e:"The buzz / electric energy between two people together",ctx:"Sudanese word for the particular energy or buzz that happens when two specific people are together — the crowd feeling it, the dynamic being alive. Not general chemistry but the specific spark of a duo.",ex:"الناس بتحب الكبريش بيناتنا.",exen:"People love the energy between us.",cat:"Relationships",src:"v1",type:"Word"},
  {a:"مهمشين",p:"muhamasheen",e:"Marginalized / sidelined / overlooked",ctx:"Pushed to the edges. Used for the artist's early days — sitting outside the group.",ex:"كنا شباب مهمشين في الجامعة، قاعدين برا.",exen:"We were marginalized youth at university, standing outside.",cat:"Identity",src:"v1",type:"Word"},
  {a:"نفسية",p:"nafseeyya",e:"Mental / emotional state",ctx:"Used constantly. 'نفسيتو كانت صعبة' = his mental state was difficult.",ex:"نفسيتو كانت صعبة في الفترة دي.",exen:"His mental state was difficult during that period.",cat:"Inner world",src:"v1",type:"Word"},
  {a:"إحساس",p:"ehsas",e:"Feeling / emotion / gut sense",ctx:"One of the most used words. Gut feelings, emotional experiences.",ex:"الإحساس بالفقد صعب شديد.",exen:"The feeling of loss is very difficult.",cat:"Inner world",src:"v1",type:"Word"},
  {a:"التوقعات — عدو الإنسان",p:"tawaqqu3at — 3aduw al-insan",e:"Expectations are the enemy of the person",ctx:"Solja's key insight. Expectations always set you up for disappointment.",ex:"التوقعات دايماً عدو الإنسان.",exen:"Expectations are always the enemy of a person.",cat:"Wisdom",src:"v1",type:"Phrase"},
  {a:"ما عارف اللي ما عارفه",p:"ma 3arif alli ma 3arfu",e:"You don't know what you don't know",ctx:"Humility about the unknown. You can't see the doors that could open.",ex:"أنت ما عارف الأبواب اللي ممكن تفتح.",exen:"You don't know the doors that could open.",cat:"Wisdom",src:"v1",type:"Phrase"},
  {a:"النجاح والفشل مترادفين",p:"an-najah wal-fashal mutaradifeen",e:"Success and failure are intertwined",ctx:"Solja's philosophy — they always come together like day and night.",ex:"النجاح والفشل مترادفين زي الليل والنهار.",exen:"Success and failure are intertwined like night and day.",cat:"Wisdom",src:"v1",type:"Phrase"},
  {a:"الدوافع",p:"ad-dawa fi3",e:"Motivations / driving forces / your 'why'",ctx:"What propels you. 'You rise by naming your motivations.'",ex:"الزول الناجح بيعرف دوافعه كويس.",exen:"A successful person knows their motivations well.",cat:"Inner world",src:"v1",type:"Word"},
  {a:"الانتشار الواسع",p:"al-intishar al-wasi3",e:"Wide reach / going viral",ctx:"When an artist's music reaches far beyond the original circle.",ex:"الانتشار الواسع جا بسرعة وكان مفاجأة.",exen:"The wide reach came fast and was a surprise.",cat:"Fame",src:"v1",type:"Phrase"},
  {a:"بقى بوزة زيادة",p:"biqa boza ziyada",e:"Became too much / blew up more than expected",ctx:"When attention or fame arrives in overwhelming quantities.",ex:"الانتشار لما جا بقى بوزة زيادة.",exen:"When the reach came it became too much.",cat:"Fame",src:"v1",type:"Phrase"},
  {a:"متمرد",p:"mutamarrid",e:"Rebellious / refusing to conform",ctx:"Used positively — always wanting to do things differently from the crowd.",ex:"من صغره كان متمرد وما بتاع القطيع.",exen:"From a young age he was rebellious and not a follower.",cat:"Character",src:"v1",type:"Word"},
  {a:"صعب الرضا",p:"sa3b ar-rida",e:"Hard to please / never easily satisfied",ctx:"Someone with very high standards who needs exactly the right thing.",ex:"أنا دايماً صعب الرضا — ما بلقى حاجة تعجبني بسرعة.",exen:"I'm always hard to please — I don't get impressed quickly.",cat:"Character",src:"v1",type:"Phrase"},
  {a:"تطور من نفسي",p:"tatawwar min nafsi",e:"I develop myself / I grow from within",ctx:"Self-directed growth without waiting for external push.",ex:"دايماً بحاول أتطور من نفسي.",exen:"I always try to develop myself.",cat:"Growth",src:"v1",type:"Phrase"},
  {a:"كمّل المشوار",p:"kammil al-mishwar",e:"Complete the journey / see it through",ctx:"Powerful encouragement phrase. 'Keep going — finish what you started.'",ex:"كمّلوا المشوار — لسه قدامكم كتير.",exen:"Complete the journey — there's still a lot ahead.",cat:"Encouragement",src:"v1",type:"Phrase"},
  {a:"لسه في البداية",p:"lissa fi al-bidaya",e:"Still at the beginning / still early days",ctx:"Perspective-giving phrase. 'You haven't seen anything yet.'",ex:"أنتم لسه في البداية والرحلة ستكون عظيمة.",exen:"You're still at the beginning and the journey will be great.",cat:"Encouragement",src:"v1",type:"Phrase"},
  {a:"السلاح بتاعي",p:"as-silah bata3i",e:"My weapon / my tool of survival",ctx:"Music as a weapon — what Solja kept when he had to flee.",ex:"المزيكة كانت السلاح بتاعي لما خرجت.",exen:"Music was my weapon when I left.",cat:"Sudan",src:"v1",type:"Phrase"},
  {a:"لهجة بيضاء",p:"lahja bayda",e:"Clear / neutral dialect — broadly understood",ctx:"A dialect accessible to wider audiences. A strategic choice for reach.",ex:"بدأت أتكلم بلهجة أبيض عشان الأوديينس الأكبر.",exen:"I started speaking more clearly for the wider audience.",cat:"Language",src:"v1",type:"Phrase"},
  {a:"نمثّل",p:"numaththil",e:"We represent / we stand for something",ctx:"Being an ambassador for your culture or community.",ex:"إحنا قاعدين نمثّل ثقافتنا برّا.",exen:"We are representing our culture outside.",cat:"Identity",src:"v1",type:"Word"},
  {a:"أوفر ثينكر",p:"over thinker",e:"Overthinker",ctx:"English loanword used naturally. Someone who overanalyzes small situations.",ex:"هو زول أوفر ثينكر — موقف صغير بيقعده يفكر فيه كتير.",exen:"He's an overthinker — a small situation has him thinking for ages.",cat:"Character",src:"v1",type:"Word"},
  {a:"برايفت وينز",p:"private wins",e:"Private victories — wins not visible to others",ctx:"Not every success is public. Internal growth and private wins count.",ex:"في نجاحات بعيدة عن الناس — برايفت وينز.",exen:"There are successes away from people — private wins.",cat:"Wisdom",src:"v1",type:"Phrase"},
  {a:"ضابط",p:"daabid",e:"Wait / hold on / steady",ctx:"Telling someone to pause. 'ضابط في الحتة دي' = hold on about that. Used to manage expectations.",ex:"بقول للناس ضابط — الكلام ده ما هيمشي.",exen:"I tell people hold on — that talk won't go anywhere.",cat:"Everyday",src:"v1",type:"Word"},
  {a:"شلة / شلتي",p:"shalla / shalliti",e:"Crew / tight friend group / my gang",ctx:"شلة = a tight informal friend group. More affectionate than أصحاب. شلتي = my crew.",ex:"شلتي صغيرة ومحدودة وأنا راضي بكدا.",exen:"My crew is small and limited and I'm fine with that.",cat:"Relationships",src:"v1",type:"Word"},
  {a:"بلو تويست",p:"blue twist",e:"A plot twist / an unexpected turn",ctx:"English loanword used naturally in Sudanese speech for a life-changing surprise.",ex:"حصل لي بلو تويست في حياتي — ما كنت قادر أستوعب.",exen:"A plot twist happened in my life — I couldn't comprehend.",cat:"Life",src:"v1",type:"Phrase"},
  {a:"ما قادر أستوعب",p:"ma qadir astaw3ib",e:"Can't comprehend / can't process it",ctx:"When something is so surprising or overwhelming it can't be absorbed.",ex:"حصل حاجة ما قادر أستوعبها لحد الآن.",exen:"Something happened I still can't comprehend.",cat:"Inner world",src:"v1",type:"Phrase"},
  {a:"المجال بطبيعته أجريسيف",p:"al-majaal bi-tabi3tuh aggressive",e:"The field is naturally aggressive / competitive",ctx:"Solja explaining why rappers are confrontational — the genre demands it, not personal character.",ex:"المجال بطبيعته أجريسيف — ده اللي الأوديينس بيمشي له.",exen:"The field is naturally aggressive — that's what the audience gravitates toward.",cat:"Industry",src:"v1",type:"Phrase"},
  {a:"الإخلاص بيبيّن في المواقف",p:"al-ikhlaas biyibayyin fi al-mawaqif",e:"Sincerity shows in moments not in words",ctx:"One of the deepest wisdom lines from the episode. What someone actually does under pressure reveals who they are.",ex:"الإخلاص بيبيّن في المواقف مش في الكلام.",exen:"Sincerity shows in moments not in words.",cat:"Wisdom",src:"v1",type:"Phrase"},
  {a:"احنا على العهد ده",p:"ahna 3ala al-3ahd da",e:"We're true to this bond / we're on this covenant",ctx:"Affirming a deep mutual commitment. العهد = a solemn bond/covenant. Used about Solja and Montiago.",ex:"احنا على العهد ده — ما في شك.",exen:"We're true to this bond — no doubt.",cat:"Relationships",src:"v1",type:"Phrase"},
  {a:"راسه قعب",p:"raasuh qa3ab",e:"His head is deep / he's a profound thinker",ctx:"Highest Sudanese intellectual compliment. قعب = deep like a bowl. Used for Montiago.",ex:"الزول ده راسه قعب شديد — كلامه عميق.",exen:"That person's head is very deep — what he says is profound.",cat:"Praise",src:"v1",type:"Phrase"},
  {a:"ما في كلمات توصف",p:"ma fi kalimaat tawsif",e:"There are no words to describe it",ctx:"Beyond language. Used for deepest appreciation or overwhelming emotion.",ex:"ما في كلمات ممكن توصف اللي بيناتنا.",exen:"There are no words that can describe what's between us.",cat:"Emphasis",src:"v1",type:"Phrase"},
  {a:"على الصعيد الشخصي والإنساني",p:"3ala as-sa3eed ash-shakhsi wal-insaani",e:"On a personal and human level",ctx:"Formal but warm framing. الصعيد = level/plane. Adds weight to personal appreciation.",ex:"على الصعيد الشخصي والإنساني — الزول ده مختلف.",exen:"On a personal and human level — this person is different.",cat:"Social",src:"v1",type:"Phrase"},
  {a:"احتككت بهم",p:"ihtakakt bihum",e:"Came in contact with them / rubbed shoulders with",ctx:"Meaningful contact — people whose lives intersected with yours and left a mark.",ex:"من أكثر الناس اللي احتككت بهم في الدنيا.",exen:"Among the most people I've come in contact with in life.",cat:"Relationships",src:"v1",type:"Phrase"},
  {a:"ما حياخد حقه",p:"ma hayaakhud haqquh",e:"Won't get his full due",ctx:"About recognition that hasn't arrived yet. Often about someone ahead of their time.",ex:"ما أعتقد إنه هو حياخد حقه 100% في الفترة دي.",exen:"I don't think he'll get his full due 100% in this period.",cat:"Industry",src:"v1",type:"Phrase"},
  {a:"لما نبقى قصة",p:"lamma nibqa qissa",e:"When we become a story / when history is written",ctx:"Visionary framing — when future generations tell this era's story.",ex:"لما نبقى قصة — حيكون من أبطاله.",exen:"When we become a story — he'll be one of its heroes.",cat:"Legacy",src:"v1",type:"Phrase"},
  {a:"من أبطاله ومن أساطيره",p:"min abtaluh w-min asaatiiruh",e:"Among its heroes and its legends",ctx:"The highest historical tribute. أبطال = heroes. أساطير = legends.",ex:"لما نبقى قصة حيكون من أبطاله ومن أساطيره.",exen:"When we become a story he'll be among its heroes and legends.",cat:"Legacy",src:"v1",type:"Phrase"},
  {a:"ببرّش",p:"bibarrish",e:"Celebrate / revel in",ctx:"Sudanese verb for celebrating or reveling. ببرّش الفشل = I celebrate failure.",ex:"أنا ببرّش الفشل زي ما ببرّش النجاح.",exen:"I celebrate failure the same way I celebrate success.",cat:"Wisdom",src:"v1",type:"Word"},
  {a:"وقت تجهيزي",p:"waqt tajheezi",e:"My preparation time / building phase",ctx:"When Solja goes quiet it's deliberate preparation, not absence. Often misread as burnout.",ex:"لما بكون مختفي — ده دايماً وقت تجهيزي.",exen:"When I'm gone quiet — that's always my preparation time.",cat:"Creative field",src:"v1",type:"Phrase"},
  {a:"مختفي",p:"mukhtafi",e:"Disappeared / gone quiet / off the radar",ctx:"Deliberately going off radar to prepare or create. Intentional not avoidant.",ex:"الوقت اللي بكون فيه مختفي ده وقت تجهيزي.",exen:"When I'm gone quiet it's always preparation time.",cat:"Creative field",src:"v1",type:"Word"},
  {a:"حماس بداية",p:"hamaas bidaaya",e:"Beginning enthusiasm / initial excitement only",ctx:"The energy at the start of something before the real sustained effort kicks in. Usually fades.",ex:"90% من الناس الموضوع بيكون عبارة عن حماس بداية بس.",exen:"90% of people it's just beginning enthusiasm.",cat:"Wisdom",src:"v1",type:"Phrase"},
  {a:"ما عارف وين بديت وين خلصت",p:"ma 3arif wayn badit wayn khalast",e:"Don't know where one started and the other ended",ctx:"When two things blend completely — used about his dual identity as Osama and Solja.",ex:"ما عارف وين بتخلص أسامة وين بتبدأ سولجا.",exen:"Don't know where Osama ends and where Solja begins.",cat:"Identity",src:"v1",type:"Phrase"},
  {a:"بالتصور اللي خطّوا ليها",p:"bit-tasawwur alli khattuu liha",e:"With the vision they originally planned for it",ctx:"Executing on exactly the vision you mapped out at the beginning. نادي من بيفعل كده.",ex:"نادي ناس بتعمل الحاجة بالتصور اللي خطّت ليها من بدري.",exen:"Rare are people who do a thing with the exact vision they planned.",cat:"Work ethic",src:"v1",type:"Phrase"},
  {a:"سرحان في الملكوت",p:"sarhan fi al-malakoot",e:"Wandering in the heavens / lost in a dreamy world",ctx:"Said affectionately about someone who daydreams or seems spiritually elsewhere. The host said it about Solja.",ex:"ما بكون سرحان في الملكوت — بكون بخطط.",exen:"I'm not wandering in the heavens — I'm planning.",cat:"Character",src:"v1",type:"Phrase"},
  {a:"ما ممكن نشوف فيها سودانيين قبل كده",p:"ma mumkin nshoof fiha sudaniyyeen qabl kida",e:"Couldn't have seen Sudanese in these places before",ctx:"Marking how far Sudanese artists have come — performing at venues previously inaccessible.",ex:"سولدي اكس بي — ما كان ممكن نشوف فيها سودانيين قبل كده.",exen:"Sold-out concerts — couldn't have seen Sudanese there before.",cat:"Sudan",src:"v1",type:"Phrase"},
  {a:"نعزز لضيوفنا",p:"nu3azziz li-duyuufna",e:"We hype up / we encourage our guests",ctx:"What Wansa does — the fقرة التعزيز is about building up guests with genuine praise.",ex:"دايماً بنعزز لضيوفنا في البودكاست.",exen:"We always hype up our guests in the podcast.",cat:"Podcast",src:"v1",type:"Phrase"},
  {a:"شكرا لانك زولك",p:"shukran li-innak zoolak",e:"Thank you for being who you are",ctx:"Gratitude phrased as appreciation for someone's authentic self. زولك = your person/self.",ex:"شكراً لك وشكراً لأنك زولك.",exen:"Thank you and thank you for being who you are.",cat:"Social",src:"v1",type:"Phrase"},
];

const V2=[
  {a:"فيري فيري سبيشال",p:"very very special",e:"Very very special (English used naturally)",ctx:"How the host describes this episode. English loanwords are totally natural in Sudanese speech.",ex:"الحلقة دي فيري فيري سبيشال بالنسبة لي.",exen:"This episode is very very special to me.",cat:"Expressions",src:"v2",type:"Phrase"},
  {a:"كتكوتة ولذيذة وبطوطة",p:"katkoota wa lazeeza wa batota",e:"Cute, delicious, adorable — stacked endearment",ctx:"Three compliments stacked together. A very Sudanese way of expressing deep affection.",ex:"هي كتكوتة ولذيذة وبطوطة.",exen:"She's cute, delicious, and adorable.",cat:"Endearment",src:"v2",type:"Phrase"},
  {a:"تشيل قطعة من قلبي",p:"tishil qit3a min qalbi",e:"Takes a piece of my heart",ctx:"Deep affection — someone holds a special irreplaceable place.",ex:"الزول دا بشيل قطعة من قلبي بجد.",exen:"That person genuinely takes a piece of my heart.",cat:"Endearment",src:"v2",type:"Phrase"},
  {a:"منوّرة كثر خيرك",p:"munawwara kathar khayrak",e:"You've brightened the place, bless you",ctx:"Warm welcome phrase for a guest. 'You've lit up the place.'",ex:"منوّرة كثر خيرك يا علا.",exen:"You've brightened the place, bless you Ala.",cat:"Social",src:"v2",type:"Phrase"},
  {a:"فقرة التعزيز",p:"faqrat at-ta3zeez",e:"The hype / compliment segment",ctx:"A recurring podcast segment where the host praises the guest enthusiastically.",ex:"احنا في فقرة التعزيز.",exen:"We're in the hype segment.",cat:"Podcast",src:"v2",type:"Phrase"},
  {a:"أتمالك نفسي",p:"atmallak nafsi",e:"Control myself / hold it together",ctx:"Used when struggling to stay composed — too excited, emotional, or overwhelmed.",ex:"بحاول أتمالك نفسي الحلقة دي.",exen:"I'm trying to hold it together this episode.",cat:"Inner world",src:"v2",type:"Phrase"},
  {a:"نخش في الموضوع",p:"nakhush fi al-mawdoo3",e:"Let's get into it / let's dive in",ctx:"Signals transitioning from small talk into the real content.",ex:"خلاص — نخش في الموضوع.",exen:"Alright — let's get into it.",cat:"Transitions",src:"v2",type:"Phrase"},
  {a:"لسه ما اتفتحت فولي",p:"lissa ma itfatahat fully",e:"Hasn't fully opened up yet",ctx:"English 'fully' mixed with Arabic. Something emerging but not yet fully developed.",ex:"السودان لسه ما اتفتح فولي للكونتنت.",exen:"Sudan hasn't fully opened up to content yet.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"التقبّل للحاجة دي",p:"at-taqabbul lil-haga di",e:"Acceptance of this thing",ctx:"Societal acceptance of something new.",ex:"المجتمع لسه ما عنده التقبل للحاجة دي.",exen:"Society still doesn't have acceptance of this thing.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"الموضوع ده خُلعة",p:"al-mawdoo3 da khul3a",e:"This thing is shocking / scary / a jolt",ctx:"Describes something that feels shocking — especially a new social norm.",ex:"فكرة البنت تطلع تعمل فيديوهات — الموضوع ده خلعة.",exen:"The idea of a girl going out making videos — it's shocking.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"دوب بدأت تتعود",p:"doob bada'at tit3awwad",e:"Just barely starting to get used to it",ctx:"'Dob' = just barely. Something at the very beginning of normalization.",ex:"الناس دوب بدأت تتعود على الكونتنت السوداني.",exen:"People are just barely starting to get used to Sudanese content.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"بكره كلمة إنفلونسر",p:"bakra kalimat influencer",e:"I hate the word 'influencer'",ctx:"Ala's strong stance. The word feels too big and carries too much responsibility.",ex:"بكره كلمة إنفلونسر — فيها مسؤولية كتير.",exen:"I hate the word influencer — it carries a lot of responsibility.",cat:"Identity",src:"v2",type:"Phrase"},
  {a:"فيها مسؤولية شديدة",p:"fiha mas'uliyya shadida",e:"It carries massive responsibility",ctx:"About labels or roles that come with serious weight.",ex:"كلمة إنفلونسر فيها مسؤولية شديدة.",exen:"The word influencer carries massive responsibility.",cat:"Values",src:"v2",type:"Phrase"},
  {a:"ما فيها تعظيم لنفسك",p:"ma fiha ta3zeem li-nafsak",e:"Doesn't inflate your ego",ctx:"Choosing a humbler label over an impressive-sounding one.",ex:"بقول بعمل سوشيال ميديا — ما فيها تعظيم لنفسك.",exen:"I say I do social media — no self-glorification in that.",cat:"Values",src:"v2",type:"Phrase"},
  {a:"دفنتلي",p:"dafantili",e:"It settled deep in me / it really landed",ctx:"When something someone said hit you hard and stayed with you.",ex:"كلامك من ناحية المسؤولية دفنتلي بجد.",exen:"What you said about responsibility really settled deep in me.",cat:"Inner world",src:"v2",type:"Word"},
  {a:"بقدم انترتينمنت — لا أكثر لا أقل",p:"baqaddim entertainment la akthar la aqal",e:"I provide entertainment — no more, no less",ctx:"Ala's clear framing of her role. Setting honest expectations.",ex:"شايفة نفسي بقدم انترتينمنت — لا أكثر لا أقل.",exen:"I see myself providing entertainment — no more, no less.",cat:"Identity",src:"v2",type:"Phrase"},
  {a:"الناس بتتأثر بشكلي وبلبسي",p:"an-nas bittit'athar bi-shakli wa bilbisi",e:"People get influenced by my appearance and clothes",ctx:"The moment Ala realized her style choices affect real people.",ex:"ما تخيلت إنه الناس حتتأثر بشكلي وبلبسي.",exen:"I didn't imagine people would be influenced by my appearance.",cat:"Influence",src:"v2",type:"Phrase"},
  {a:"زي أنا بلقى الشعر في الأكل",p:"zay ana balqa ash-shi3r fi al-akl",e:"Like I find poetry in food",ctx:"Ala's beautiful description of her food content style.",ex:"طريقة كلامي في الأكل — زي أنا بلقى الشعر في الأكل.",exen:"My way of talking about food — like I find poetry in it.",cat:"Artistry",src:"v2",type:"Phrase"},
  {a:"ما في إنسان ممكن يوريك كل شخصياته",p:"ma fi insan mumkin yawrreek kull shakhsiyyatuh",e:"No person can show you all their sides",ctx:"Key insight about social media. What you see is just one side.",ex:"ما في إنسان ممكن يوريك كل شخصياته في السوشال ميديا.",exen:"No person can show you all their sides on social media.",cat:"Wisdom",src:"v2",type:"Phrase"},
  {a:"الأوديينس بتفاعل لما أكون على طبيعتي",p:"al-audience bittifa3al lamma akun 3ala tabi3ti",e:"The audience engages when I'm in my natural state",ctx:"Authenticity drives engagement more than performance.",ex:"الأوديينس بتفاعل معي أكتر لما أكون على طبيعتي.",exen:"The audience engages more when I'm in my natural state.",cat:"Social media",src:"v2",type:"Phrase"},
  {a:"بتخليني أحبط",p:"bittkhallini ahbat",e:"It makes me feel defeated / want to quit",ctx:"The emotional effect of negative feedback.",ex:"الكومنتس دي بتخليني أحبط شديدة.",exen:"Those comments make me feel very defeated.",cat:"Inner world",src:"v2",type:"Phrase"},
  {a:"الكومنت بيرفع لك الفيديو",p:"al-comment biyirfa3 lak al-video",e:"The comment boosts your video (algorithm)",ctx:"Any engagement — even negative — boosts the algorithm.",ex:"حتى الكومنت السلبي بيرفع لك الفيديو.",exen:"Even a negative comment boosts your video.",cat:"Social media",src:"v2",type:"Phrase"},
  {a:"كل ما تكبر كل ما حياتك بتزيد",p:"kull ma tikbar kull ma hayatak bitzeed",e:"The more you grow the more your life expands",ctx:"Growth brings complexity. More fame = more life = more to manage.",ex:"كل ما تكبر كل ما حياتك بتزيد وبيزيد معها الضغط.",exen:"The more you grow the more your life and pressures expand.",cat:"Growth",src:"v2",type:"Phrase"},
  {a:"من حقه يقول",p:"min haqquh yaqool",e:"He has the right to say / it's his right",ctx:"Validating someone's right to their opinion — even a negative one.",ex:"من حقه يقول ما شاء — ده رأيه.",exen:"He has the right to say whatever — that's his opinion.",cat:"Mindset",src:"v2",type:"Phrase"},
  {a:"ما في إنسان حتفرضي عليه",p:"ma fi insan hattifridee 3aleh",e:"You can't force anyone to accept you",ctx:"You can't make people like you. Accepting this = freedom.",ex:"ما في إنسان حتفرضي عليه إنه يحبك.",exen:"There's no person you can force to like you.",cat:"Mindset",src:"v2",type:"Phrase"},
  {a:"اللي انفلونس من مرباه",p:"alli influenced min marabbah",e:"Influenced by their upbringing",ctx:"How someone was raised shapes what they accept and reject.",ex:"ناس كتير اللي انفلونس من مرباهم بيرفضوا الحاجة دي.",exen:"Many people influenced by their upbringing reject this.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"تخطينا النقطة دي",p:"takhatteyna an-nuqta di",e:"We've passed that point / moved beyond that",ctx:"Used when society has evolved past a previous issue.",ex:"تخطينا النقطة دي — الناس بدأت تتقبل.",exen:"We've passed that point — people started accepting.",cat:"Transitions",src:"v2",type:"Phrase"},
  {a:"ما عندنا ناس يمثلوننا",p:"ma 3andna nas yumassalunna",e:"We don't have people who represent us",ctx:"The gap in Sudanese representation. No drama, cinema, public figures in mainstream media.",ex:"ما عندنا ناس يمثلوننا زي بقية البلدان.",exen:"We don't have people who represent us like other countries.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"ابتدى يفتح نفسه للعالم",p:"ibtada yiftah nafsu lil-3alam",e:"Started opening itself to the world",ctx:"Sudan (or any closed community) beginning to open up and engage globally.",ex:"السودان ابتدى يفتح نفسه للعالم.",exen:"Sudan started opening itself to the world.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"فقرة الشمار",p:"faqrat ash-shamar",e:"The gossip / tea segment",ctx:"A recurring podcast segment for sharing gossip or awkward stories.",ex:"احنا في فقرة الشمار — جيبي القصة.",exen:"We're in the gossip segment — bring the story.",cat:"Podcast",src:"v2",type:"Phrase"},
  {a:"موقف بايخ",p:"mawqif bayikh",e:"A bad / awkward / uncomfortable situation",ctx:"بايخ = bad, lame, off.",ex:"حصل ليّ موقف بايخ مع زول مشهور.",exen:"I had a bad situation with a famous person.",cat:"Everyday",src:"v2",type:"Phrase"},
  {a:"عملت رايحة منّي",p:"3amalat raiha minni",e:"She dismissed me / walked off on me",ctx:"When someone turns their back and leaves without acknowledging you.",ex:"سلمت عليها وعملت رايحة منّي.",exen:"I greeted her and she dismissed me.",cat:"Social",src:"v2",type:"Phrase"},
  {a:"عملتها كفان",p:"3amalatha kafan",e:"She gave me the cold shoulder",ctx:"When someone acts completely dead to you — totally ignores you.",ex:"حست إنها عملتها كفان وعدّت.",exen:"I felt she gave me the cold shoulder.",cat:"Social",src:"v2",type:"Phrase"},
  {a:"خُذ للزول العذر",p:"khuz lil-zool al-3uzur",e:"Give the person an excuse / benefit of the doubt",ctx:"Key advice: give people a reason for bad behavior — for YOUR sake, not theirs.",ex:"خُذ للزول العذر عشان نفسيتك تريح.",exen:"Give the person an excuse so your mind can rest.",cat:"Wisdom",src:"v2",type:"Phrase"},
  {a:"رجع روحك لورا",p:"raji3 rohak lawwra",e:"Step back and see what's best for you",ctx:"Self-care advice: step back, assess the situation, and choose your wellbeing.",ex:"رجع روحك لورا وشوف وات إز بست فور يو.",exen:"Step back and see what's best for you.",cat:"Wisdom",src:"v2",type:"Phrase"},
  {a:"الوضع الحاصل",p:"al-wad3 al-hasil",e:"The current situation / what's happening now",ctx:"Refers to the current state of affairs — the war, life circumstances, whatever is ongoing.",ex:"الوضع الحاصل صعب على كل الناس.",exen:"The current situation is difficult for everyone.",cat:"Context",src:"v2",type:"Phrase"},
  {a:"النفسيات ذات",p:"an-nafseeyat zat",e:"The mental state itself — on its own",ctx:"Emphasizing that the mental/emotional state is its own independent challenge.",ex:"النفسيات ذات صعبة — خلّي بالك من نفسك.",exen:"The mental state itself is difficult — take care of yourself.",cat:"Inner world",src:"v2",type:"Phrase"},
  {a:"أوفق بين شغلي وبين كونتنت",p:"awaffiq bayn shughli wa bayn content",e:"Balance between my job and my content",ctx:"The real challenge of being a content creator alongside a full-time job.",ex:"صعب أوفق بين شغلي وبين الكونتنت.",exen:"It's difficult to balance my job and my content.",cat:"Work-life",src:"v2",type:"Phrase"},
  {a:"الطبيخ ما زي أي كونتنت",p:"at-tabikh ma zay ay content",e:"Cooking isn't like any other content",ctx:"Cooking requires planning, preparation, filming, and editing — multiple days per video.",ex:"الطبيخ ما زي أي كونتنت — بياخذ يوم تخطيط ويوم إعداد.",exen:"Cooking isn't like any content — takes a planning day and a prep day.",cat:"Work-life",src:"v2",type:"Phrase"},
  {a:"ما حضغط على نفسي",p:"ma haddghut 3ala nafsi",e:"I won't pressure myself",ctx:"Setting a self-care boundary. Not forcing yourself to produce when you can't.",ex:"ما حضغط على نفسي عشان أطلع كونتنت.",exen:"I won't pressure myself to put out content.",cat:"Self-care",src:"v2",type:"Phrase"},
  {a:"خُدي روحك برييك",p:"khudi rohak break",e:"Give yourself a break",ctx:"Arabic 'roha' (soul/self) + English 'break' — very natural mix.",ex:"خُدي روحك برييك — الحياة بتجي مع الحياة.",exen:"Give yourself a break — life comes with life.",cat:"Self-care",src:"v2",type:"Phrase"},
  {a:"الحياة بتجي مع الحياة",p:"al-hayat bituji ma3 al-hayat",e:"Life comes with life / things unfold naturally",ctx:"Things work themselves out as you live. You don't have to force everything.",ex:"ما ضغطي على نفسك — الحياة بتجي مع الحياة.",exen:"Don't pressure yourself — life comes with life.",cat:"Wisdom",src:"v2",type:"Phrase"},
  {a:"أهلك روحي",p:"ahlik rohi",e:"Destroy myself / burn myself out",ctx:"What happens when you force yourself to do things you hate.",ex:"لو ضغطت على نفسي حأهلك روحي.",exen:"If I pressure myself I'll destroy myself.",cat:"Self-care",src:"v2",type:"Phrase"},
  {a:"حبّوا اللي بتعملوه جنونياً",p:"habbu alli bita3maluhu junuuniyyan",e:"Love what you do — madly, with full passion",ctx:"Ala's closing advice. Don't just like it — love it madly. That passion sustains you.",ex:"حبّوا اللي بتعملوه جنونياً والقوا روحكم فيه.",exen:"Love what you do madly and throw yourselves into it.",cat:"Encouragement",src:"v2",type:"Phrase"},
  {a:"القوا روحكم فيه",p:"alqu rohkum fih",e:"Throw yourself into it / put your whole soul in",ctx:"Total commitment — don't hold back. Give yourself completely to what you love.",ex:"لما بتحبوا حاجة، القوا روحكم فيها.",exen:"When you love something, throw your whole soul into it.",cat:"Encouragement",src:"v2",type:"Phrase"},
  {a:"ما تخافوا من النجاح",p:"ma tkhafoo min an-najah",e:"Don't be afraid of success",ctx:"People often self-sabotage because they fear what success brings.",ex:"ما تخافوا من النجاح — لو بتحبوا الحاجة دي وصلوا بها.",exen:"Don't be afraid of success — if you love this thing, take it all the way.",cat:"Encouragement",src:"v2",type:"Phrase"},
  {a:"الإنسان بيخاف ينجح",p:"al-insan bikhaf yinjah",e:"A person is afraid to succeed",ctx:"The paradox: people often fear success more than failure.",ex:"الناس مرات بتوقف نفسها — الإنسان بيخاف ينجح.",exen:"People sometimes stop themselves — a person is afraid to succeed.",cat:"Psychology",src:"v2",type:"Phrase"},
  {a:"حيكسروك",p:"haykissrook",e:"They'll try to break you",ctx:"What haters try to do. If you love what you do, you can't be broken.",ex:"الناس حتكسروك بس لو بتحب الحاجة دي ما حيقدروا.",exen:"People will try to break you but if you love this they won't be able to.",cat:"Resilience",src:"v2",type:"Word"},
  {a:"شوف التحت وصل وين",p:"shoof at-taht wisal ween",e:"Look how far the bottom has come / look at your progress",ctx:"Ala's closing challenge — look back at where you started. Gratitude for growth.",ex:"شوف التحت وصل وين — ما تنسى من وين بدأت.",exen:"Look how far the bottom has come — don't forget where you started.",cat:"Encouragement",src:"v2",type:"Phrase"},
  {a:"على طبيعتك",p:"3ala tabi3tak",e:"In your natural state / being fully yourself",ctx:"When you're natural, people connect. When you perform, they feel it.",ex:"لما تكون على طبيعتك الناس بتحبك أكتر.",exen:"When you're in your natural state people love you more.",cat:"Authenticity",src:"v2",type:"Phrase"},
  {a:"يتحدّوا النورم",p:"yittahaddaw an-norm",e:"Challenge the norm / push against conventions",ctx:"Going against what society says is normal. A key theme of both podcasts.",ex:"لازم نتحدّى النورم ونعمل اللي إحنا بنحبه.",exen:"We must challenge the norm and do what we love.",cat:"Society",src:"v2",type:"Phrase"},
  {a:"عندك حاجة حلوة عايز توريها للعالم",p:"3andak haga helwa 3ayiz tawwarriyha lil-3alam",e:"You have something beautiful to show the world",ctx:"The core motivation for creating — you have something valuable to share.",ex:"لو عندك حاجة حلوة عايز توريها للعالم — طلّعها.",exen:"If you have something beautiful you want to show the world — put it out.",cat:"Motivation",src:"v2",type:"Phrase"},
  {a:"برجع وبقول لنفسي",p:"barji3 wa baqool li-nafsi",e:"I go back and tell myself / I check in with myself",ctx:"Self-talk. Returning to your own internal voice before reacting to others.",ex:"برجع وبقول لنفسي — هل الحاجة دي حقيقي بتأثر فيّ؟",exen:"I go back and tell myself — is this really affecting me?",cat:"Mindset",src:"v2",type:"Phrase"},
  {a:"عايزة أطوّر من نفسي",p:"3ayza atawwir min nafsi",e:"I want to develop myself / grow as a creator",ctx:"Desire for self-improvement and growth in content quality.",ex:"عايزة أطوّر من نفسي ومش أنزل نفس الحاجة دايماً.",exen:"I want to develop myself and not always put out the same thing.",cat:"Growth",src:"v2",type:"Phrase"},
  {a:"في حاجات كثيرة تغيّرت فجأة",p:"fi hagat katira ghayyarat faj'a",e:"Many things changed suddenly",ctx:"Life circumstances shifting quickly. Everything changing at once unexpectedly.",ex:"في حاجات كتيرة تغيّرت فجأة في حياتي.",exen:"Many things changed suddenly in my life.",cat:"Life",src:"v2",type:"Phrase"},
];

